from pybricks.hubs import PrimeHub
from pybricks.parameters import Axis, Direction, Port, Stop
from pybricks.pupdevices import ColorSensor, Motor
from pybricks.robotics import DriveBase
from pybricks.tools import StopWatch, multitask, run_task, wait

# Set up all devices.
hub = PrimeHub(top_side=Axis.Z, front_side=Axis.X)
Casovac = StopWatch()
color_sensor = ColorSensor(Port.B)
Right = Motor(Port.E, Direction.CLOCKWISE)
Left = Motor(Port.F, Direction.COUNTERCLOCKWISE)
RukaRight = Motor(Port.D, Direction.CLOCKWISE)
RukaLeft = Motor(Port.C, Direction.COUNTERCLOCKWISE)
drive_base = DriveBase(Left, Right, 56, 81)

async def subtask():
    # jede rovne na ukol 1
    await drive_base.straight(220, then=Stop.BRAKE)
    await wait(600)
    drive_base.settings(straight_speed=100)
    await drive_base.straight(-40)

async def subtask2():
    # zvedne stolik
    await wait(600)
    await RukaRight.run_angle(1500, 200, Stop.BRAKE)
    await RukaRight.run_angle(1500, -100, Stop.BRAKE)

async def subtask3():
    await wait(600)
    await RukaLeft.run_angle(1500, 208, Stop.BRAKE)

async def Mise_1():
    await wait(0)
    # config
    # jede rovne
    drive_base.settings(straight_speed=500)
    await multitask(
        RukaLeft.run_angle(1500, -250, Stop.BRAKE),
    )
    await drive_base.straight(515, then=Stop.NONE)
    # otoci se doprava
    await drive_base.arc(200, angle=60)
    # otoci se smerem k ukolu 1
    await drive_base.turn(-117)
    await multitask(
        subtask(),
        subtask2(),
        subtask3(),
    )
    await RukaLeft.run_angle(100, -180, Stop.BRAKE)
    drive_base.settings(straight_speed=500)
    await drive_base.straight(-150)
    await drive_base.turn(55)
    await drive_base.straight(-600)

async def subtask4():
    RukaRight.control.limits(acceleration=500)
    await RukaRight.run_angle(500, -200)

async def subtask5():
    await wait(850)
    await drive_base.straight(-500)

async def Mise_2():
    await wait(0)
    # config
    drive_base.settings(turn_acceleration=75)
    drive_base.settings(turn_rate=300)
    drive_base.settings(straight_speed=200)
    # jede rovne
    await drive_base.straight(130)
    await drive_base.turn(88.5)
    # config
    drive_base.settings(straight_speed=650)
    # jede rovne
    await drive_base.straight(520)
    await multitask(
        subtask4(),
        subtask5(),
    )

async def Mise_3():
    await wait(0)
    # config
    drive_base.settings(turn_acceleration=75)
    drive_base.settings(turn_rate=300)
    drive_base.settings(straight_speed=500)
    # jede rovne
    await drive_base.straight(60)
    await drive_base.turn(9)
    await drive_base.straight(475, then=Stop.NONE)
    await drive_base.arc(240, angle=86)
    await drive_base.straight(110)
    RukaRight.control.limits(acceleration=100)
    await RukaRight.run_angle(100, -220)
    await RukaRight.run_angle(300, 220, Stop.BRAKE)
    drive_base.settings(straight_speed=40)
    await drive_base.straight(135)
    drive_base.settings(straight_speed=500)
    await drive_base.straight(510)
    await drive_base.turn(125 - drive_base.angle())
    await drive_base.straight(100)
    await RukaRight.run_angle(1500, -200, Stop.BRAKE)
    await RukaRight.run_angle(1500, 200, Stop.NONE)
    await drive_base.straight(-300)
    await drive_base.turn(-25)
    await drive_base.straight(515)
    await drive_base.turn(170 - drive_base.angle())
    await drive_base.straight(500)

async def Mise_4():
    await wait(0)
    drive_base.settings(turn_rate=40)
    drive_base.settings(straight_speed=350)
    await drive_base.straight(50)
    await drive_base.turn(-45)
    await drive_base.straight(200)
    await drive_base.turn(45)
    await drive_base.straight(405)
    drive_base.settings(straight_speed=200)
    await drive_base.turn(-25)
    await drive_base.straight(120)
    await drive_base.turn(25)
    await drive_base.straight(-90)
    await drive_base.turn(39.5)
    await drive_base.straight(320)
    await RukaLeft.run_angle(1500, -360)
    await RukaRight.run_angle(450, 520)
    await wait(150)
    await RukaRight.run_angle(300, -520)
    await RukaLeft.run_angle(1500, 390)
    await drive_base.straight(-160, then=Stop.BRAKE)
    await drive_base.turn(-50)
    await drive_base.straight(-20, then=Stop.BRAKE)
    await drive_base.turn(-25)
    await drive_base.straight(-250)

async def main():
    # toolky
    print('V:', hub.battery.voltage() / 1000, '   A:', hub.battery.current() / 1000)
    Casovac.reset()
    # setup
    drive_base.use_gyro(True)
    await multitask(
        Mise_4(),
    )


run_task(main())